'use client';

import { useEffect, useMemo, useState, useCallback } from 'react';
import { Search, Filter, MoreVertical, Plus } from 'lucide-react';

import { productBacklogService } from '@/services/productbacklog.service';
import { ProjectService } from '@/services/projectService';
import { useToast } from '@/providers/ToastProvider';

import CreateTaskModal from '@/shared/components/CreateTaskModal';
import UpdateTaskModal from '@/shared/components/UpdateTaskModal';
import CreateEpicModal from '@/shared/components/CreateEpicModal';
import StartSprintModal from '@/shared/components/StartSprintModal';
import CompleteSprintModal from '@/shared/components/CompleteSprintModal';

// ---------------------------
// Helpers
// ---------------------------
const statusToneText = {
  TODO: 'text-gray-500',
  IN_PROGRESS: 'text-blue-500',
  IN_REVIEW: 'text-amber-500',
  DONE: 'text-green-500',
};

const stringToColorTuple = (str) => {
  let hash = 0;
  for (let i = 0; i < (str?.length || 0); i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  const hue = Math.abs(hash) % 360;
  return { bg: `hsl(${hue}, 70%, 90%)`, text: `hsl(${hue}, 70%, 30%)` };
};

// ---------------------------
// Work Item Component
// ---------------------------
function WorkItem({ it, itemOrder, onClick }) {
  const statusConfig = statusToneText[it.status?.toUpperCase()] || statusToneText.TODO;

  return (
    <div
      onClick={() => onClick?.(it)}
      className='flex items-center justify-between py-3 mb-2 bg-white group hover:bg-gray-50/50 rounded-xl border-b border-transparent hover:border-gray-100 transition-colors cursor-pointer'
    >
      <div className='w-4 h-4 rounded border border-gray-300 mr-4 shrink-0' />

      <div className='w-32 shrink-0 text-[13px] text-gray-900 font-medium whitespace-nowrap pl-1 tracking-wide'>
        Issue {itemOrder || '-'}
      </div>

      <div
        className='flex-1 min-w-0 text-[13.5px] text-gray-900 font-medium truncate pr-4'
        title={it.title || it.name}
      >
        {it.title || it.name}
      </div>

      <div className={`w-28 shrink-0 text-[13px] font-medium ${statusConfig}`}>
        {it.status === 'IN_PROGRESS'
          ? 'In Progress'
          : it.status === 'IN_REVIEW'
            ? 'In Review'
            : it.status === 'TODO'
              ? 'To Do'
              : it.status || 'To Do'}
      </div>

      <div className='w-44 shrink-0 px-2 flex justify-start'>
        {it.epicName ? (
          <span className='px-2.5 py-0.5 rounded-lg text-xs font-semibold bg-purple-50 text-purple-700 truncate w-full text-center'>
            {it.epicName}
          </span>
        ) : (
          <span className='w-full'></span>
        )}
      </div>

      <div className='w-24 shrink-0 text-[13px] text-gray-500 text-center font-medium'>
        {it.dueDate ? new Date(it.dueDate).toLocaleDateString('vi-VN') : '-'}
      </div>

      <div className='w-10 shrink-0 text-[13px] text-blue-600 font-bold text-center'>
        {it.storyPoint || it.points || '-'}
      </div>

      <div
        className={`w-24 shrink-0 text-[13px] font-medium text-center ${it.priority?.toUpperCase() === 'HIGH' ? 'text-orange-500' : it.priority?.toUpperCase() === 'LOW' ? 'text-green-600' : 'text-blue-500'}`}
      >
        {it.priority === 'HIGH' ? 'High' : it.priority === 'LOW' ? 'Low' : 'Medium'}
      </div>

      <div className='w-12 shrink-0 flex justify-center'>
        <div
          className='h-6 w-6 rounded-full flex items-center justify-center text-[10px] font-bold'
          style={{
            backgroundColor: stringToColorTuple(it.assigneeName || 'U').bg,
            color: stringToColorTuple(it.assigneeName || 'U').text,
          }}
        >
          {(it.assigneeName || '?').charAt(0).toUpperCase()}
        </div>
      </div>

      <div className='w-8 shrink-0 flex justify-center text-gray-400 opacity-50 hover:opacity-100 transition-opacity'>
        <MoreVertical className='w-4 h-4' />
      </div>
    </div>
  );
}

// ---------------------------
// Column Headers
// ---------------------------
function ColumnHeaders() {
  return (
    <div className='flex items-center justify-between py-2 mb-2 bg-gray-50/80 rounded-lg px-2 border-b border-gray-100/50'>
      <div className='w-4 mr-4 shrink-0' />
      <div className='w-32 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider pl-1'>
        Issue
      </div>
      <div className='flex-1 min-w-0 text-xs font-semibold text-gray-400 uppercase tracking-wider'>
        Summary
      </div>
      <div className='w-28 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider'>
        Status
      </div>
      <div className='w-44 shrink-0 px-2 text-xs font-semibold text-gray-400 uppercase tracking-wider text-center'>
        Epic
      </div>
      <div className='w-24 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider text-center'>
        Due Date
      </div>
      <div className='w-10 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider text-center'>
        Pts
      </div>
      <div className='w-24 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider text-center'>
        Priority
      </div>
      <div className='w-12 shrink-0 text-xs font-semibold text-gray-400 uppercase tracking-wider text-center'>
        User
      </div>
      <div className='w-8 shrink-0' />
    </div>
  );
}

// ---------------------------
// Main Board Component
// ---------------------------
export default function BacklogBoard() {
  const toast = useToast();
  const [projectId, setProjectId] = useState(null);
  const [activeSprintForTask, setActiveSprintForTask] = useState(null);
  // Data State
  const [epics, setEpics] = useState([]);
  const [sprints, setSprints] = useState([]);
  const [backlogItems, setBacklogItems] = useState([]);

  const [loading, setLoading] = useState(true);
  const [selectedEpicId, setSelectedEpicId] = useState('ALL');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Modal State
  const [openCreateEpic, setOpenCreateEpic] = useState(false);
  const [openCreateTask, setOpenCreateTask] = useState(false);
  const [openUpdateTask, setOpenUpdateTask] = useState(false);
  const [selectedTask, setSelectedTask] = useState(null);
  const [openStartSprint, setOpenStartSprint] = useState(false);
  const [openCompleteSprint, setOpenCompleteSprint] = useState(false);
  const [selectedSprintAction, setSelectedSprintAction] = useState(null);

  const formatToDateOnly = (dateString) => {
    if (!dateString) return null;
    const date = new Date(dateString);
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`; // Trß║ú vß╗ü ─æ├║ng ─æß╗ïnh dß║íng YYYY-MM-DD
  };
  // Initialize Project
  useEffect(() => {
    const initProject = async () => {
      try {
        const res = await ProjectService.getAll({ PageNumber: 1, PageSize: 1 });
        if (res?.data?.items?.length > 0) {
          const id = res.data.items[0].projectId;
          setProjectId(id);
        }
      } catch {
        toast.error('Kh├┤ng lß║Ñy ─æ╞░ß╗úc project');
      }
    };
    initProject();
  }, [toast]);

  // Fetch Data
  const fetchData = useCallback(
    async (id, showLoading = true) => {
      if (!id) return;
      try {
        if (showLoading) setLoading(true);

        const [resEpics, resBacklog] = await Promise.all([
          productBacklogService.getEpics(id),
          productBacklogService.getWorkItemsBacklog(id),
        ]);

        // Parse Epics
        let epicsData = [];
        if (resEpics?.data?.items) epicsData = resEpics.data.items;
        else if (resEpics?.data) epicsData = resEpics.data;
        else if (Array.isArray(resEpics)) epicsData = resEpics;
        setEpics(Array.isArray(epicsData) ? epicsData : []);

        // Parse Sprint/Backlog
        if (resBacklog?.data) {
          setSprints(resBacklog.data.sprints || []);

          let bkItems = [];
          if (resBacklog.data.productBacklog?.items) {
            bkItems = resBacklog.data.productBacklog.items;
          } else if (resBacklog.data.items) {
            bkItems = resBacklog.data.items;
          }
          setBacklogItems(bkItems);
        }
      } catch (err) {
        console.error('Fetch Data failed:', err);
        toast.error('Lß╗ùi khi tß║úi dß╗» liß╗çu Backlog Board');
      } finally {
        setLoading(false);
      }
    },
    [toast],
  );

  useEffect(() => {
    fetchData(projectId);
  }, [projectId, fetchData]);

  // Derived Logic for Data mapping
  // Lß║Ñy t├¬n Epic ─æ├¡nh k├¿m v├áo Work Item
  const appendEpicName = (item) => {
    const found = epics.find((e) => e.id === item.parentId);
    return { ...item, epicName: found ? found.title || found.name : '' };
  };

  // Filter Logic (Apply to both sprints and backlog)
  const isSelectedEpic = (parentId) => selectedEpicId === 'ALL' || parentId === selectedEpicId;

  const filteredBacklogItems = useMemo(() => {
    return backlogItems.filter((it) => it && isSelectedEpic(it.parentId)).map(appendEpicName);
  }, [backlogItems, selectedEpicId, epics]);

  const filteredSprints = useMemo(() => {
    return sprints.map((sp) => ({
      ...sp,
      items: (sp.items || []).filter((it) => it && isSelectedEpic(it.parentId)).map(appendEpicName),
    }));
  }, [sprints, selectedEpicId, epics]);

  // Compute absolute creation order of all issues based on ID/CreatedAt
  const itemOrders = useMemo(() => {
    const allItems = [...backlogItems];
    sprints.forEach((sp) => {
      if (sp.items) allItems.push(...sp.items);
    });

    // Deduplicate
    const uniqueItemsMap = {};
    allItems.forEach((i) => {
      uniqueItemsMap[i.workItemId || i.id] = i;
    });
    const uniqueItems = Object.values(uniqueItemsMap);

    const sorted = uniqueItems.sort((a, b) => {
      const timeA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
      const timeB = b.createdAt ? new Date(b.createdAt).getTime() : 0;
      if (timeA && timeB && timeA !== timeB) return timeA - timeB;

      const idA = a.workItemId || a.id || '';
      const idB = b.workItemId || b.id || '';
      return idA.localeCompare(idB);
    });

    const map = {};
    sorted.forEach((item, idx) => {
      map[item.workItemId || item.id] = idx + 1;
    });
    return map;
  }, [backlogItems, sprints]);

  const handleSprintActionClick = (sprint, isStart) => {
    setSelectedSprintAction(sprint);
    if (isStart) {
      setOpenStartSprint(true);
    } else {
      // Thay v├¼ d├╣ng window.confirm, ta mß╗ƒ Modal chuy├¬n dß╗Ñng
      setOpenCompleteSprint(true);
    }
  };

  const handleQuickCreateSprint = async () => {
    try {
      const sprintNum = sprints.length + 1;
      const payload = {
        name: `Sprint ${sprintNum}`,
        title: `Sprint ${sprintNum}`,
      };
      const res = await productBacklogService.createSprint(projectId, payload);
      if (res && res.isSuccess === false) {
        toast.error(res.message || 'Lß╗ùi khi tß║ío Sprint');
      } else {
        toast.success('─É├ú tß║ío mß╗Öt Sprint mß╗¢i');
        fetchData(projectId);
      }
    } catch (e) {
      toast.error('Lß╗ùi khi tß║ío Sprint');
    }
  };

  return (
    <div className='flex gap-6 w-full h-[calc(100vh-140px)] bg-slate-50 relative'>
      {/* Sidebar Epics */}
      {isSidebarOpen ? (
        <div className='w-[260px] shrink-0 bg-white border border-gray-200 shadow-sm rounded-3xl p-5 flex flex-col h-full overflow-y-auto transition-all duration-300'>
          <div className='flex justify-between items-center mb-6'>
            <div className='text-[15px] font-bold text-gray-900'>Epic</div>
            <div className='flex items-center gap-3'>
              <button
                onClick={() => setIsSidebarOpen(false)}
                className='text-xs text-[#A32A2A] font-bold hover:underline'
              >
                ß║¿n
              </button>
              <button
                onClick={() => setOpenCreateEpic(true)}
                className='w-[22px] h-[22px] rounded-full bg-[#A32A2A] text-white flex items-center justify-center hover:bg-red-800 transition-colors'
                title='Tß║ío Epic'
              >
                <Plus className='w-3.5 h-3.5' />
              </button>
            </div>
          </div>

          <div className='flex flex-col gap-1'>
            <button
              onClick={() => setSelectedEpicId('ALL')}
              className={`text-left px-4 py-2.5 rounded-2xl text-[14px] font-semibold transition-colors ${
                selectedEpicId === 'ALL'
                  ? 'bg-[#F4F0FF] text-[#6333FF]'
                  : 'text-gray-700 hover:bg-gray-50'
              }`}
            >
              Tß║Ñt cß║ú
            </button>

            {epics.map((epic) => (
              <button
                key={epic.id}
                onClick={() => setSelectedEpicId(epic.id)}
                className={`text-left px-4 py-2.5 rounded-2xl text-[14px] font-semibold transition-colors ${
                  selectedEpicId === epic.id
                    ? 'bg-[#F4F0FF] text-[#6333FF]'
                    : 'text-gray-700 hover:bg-gray-50'
                }`}
              >
                <div className='truncate'>{epic.title || epic.name || 'Untitled Epic'}</div>
              </button>
            ))}
          </div>
        </div>
      ) : (
        <div className='w-12 shrink-0 bg-white border border-gray-200 shadow-sm rounded-3xl flex flex-col items-center py-6 h-full transition-all duration-300'>
          <button
            onClick={() => setIsSidebarOpen(true)}
            className='flex flex-col items-center justify-center text-gray-500 hover:text-gray-900 w-full h-full'
          >
            <span
              className='uppercase tracking-[0.3em] text-sm font-bold'
              style={{ writingMode: 'vertical-rl', transform: 'rotate(180deg)' }}
            >
              EPIC
            </span>
          </button>
        </div>
      )}

      {/* Main Board */}
      <div className='flex-1 flex flex-col min-w-0 overflow-y-auto pr-2 pb-10'>
        {/* Search / Filter Bar */}
        <div className='flex items-center gap-4 mb-6 sticky top-0 bg-slate-50 pt-1 z-10'>
          <div className='flex items-center w-[360px] h-10 px-4 rounded-full border border-gray-200 bg-white shadow-sm'>
            <Search className='w-4 h-4 text-gray-400 mr-2 shrink-0' />
            <input
              type='text'
              placeholder='T├¼m kiß║┐m'
              className='flex-1 outline-none text-sm bg-transparent placeholder-gray-400 text-gray-800'
            />
          </div>
          <button className='flex items-center gap-2 h-10 px-5 rounded-full border border-gray-200 bg-white shadow-sm hover:bg-gray-50 transition-colors text-sm font-semibold text-gray-700'>
            <Filter className='w-4 h-4 text-gray-500' />
            Bß╗Ö lß╗ìc
          </button>
        </div>

        {loading ? (
          <div className='text-center py-10 text-slate-500'>─Éang tß║úi dß╗» liß╗çu...</div>
        ) : (
          <div className='overflow-x-auto pb-4'>
            <div className='min-w-[1000px] pr-2'>
              {/* SPRINTS */}
              {filteredSprints.map((sprint) => {
                const sprintItemIds = (sprint.items || []).map((i) => i.workItemId || i.id);
                return (
                  <div
                    key={sprint.sprintId}
                    className='rounded-3xl bg-white border border-gray-100 shadow-sm p-6 mb-6'
                  >
                    {/* Header */}
                    <div className='flex items-center mb-6 pl-2 pr-1'>
                      <div className='w-4 h-4 rounded border border-gray-300 mr-4 flex-shrink-0' />
                      <h3 className='text-[16px] font-bold text-gray-900'>
                        {sprint.name || sprint.title}
                      </h3>
                      <div className='flex-1' />

                      {/* Dynamic Start/Complete Sprint button based on status */}
                      {sprint.status?.toUpperCase() === 'ACTIVE' ||
                      sprint.status?.toUpperCase() === 'IN_PROGRESS' ? (
                        <button
                          onClick={() => handleSprintActionClick(sprint, false)}
                          className='h-[34px] px-5 border border-green-200 bg-green-50 rounded-full text-[13px] font-medium text-green-700 hover:bg-green-100 transition-colors flex items-center shadow-sm'
                        >
                          Ho├án th├ánh Sprint
                        </button>
                      ) : (
                        <button
                          onClick={() => handleSprintActionClick(sprint, true)}
                          className='h-[34px] px-5 border border-gray-200 bg-white rounded-full text-[13px] font-medium text-gray-700 hover:bg-gray-50 transition-colors flex items-center shadow-sm'
                        >
                          Bß║»t ─æß║ºu Sprint
                        </button>
                      )}

                      <button className='ml-3 p-1.5 text-gray-500 hover:bg-gray-100 rounded-full transition-colors'>
                        <MoreVertical className='w-4 h-4' />
                      </button>
                    </div>

                    {/* List Container */}
                    <ColumnHeaders />
                    <div className='min-h-[20px]'>
                      {(sprint.items || []).map((it) => (
                        <WorkItem
                          key={it.workItemId || it.id}
                          it={it}
                          itemOrder={itemOrders[it.workItemId || it.id]}
                          onClick={async (task) => {
                            try {
                              const res = await productBacklogService.getWorkItemById(
                                projectId,
                                task.workItemId || task.id,
                              );
                              setSelectedTask(res?.data ? { ...task, ...res.data } : task);
                            } catch (e) {
                              console.error(e);
                              setSelectedTask(task);
                            }
                            setOpenUpdateTask(true);
                          }}
                        />
                      ))}
                    </div>

                    {/* Tß║áO NHIß╗åM Vß╗ñ D╞»ß╗ÜI SPRINT */}
                    <div className='mt-4 flex items-center'>
                      {/* Tß║áO NHIß╗åM Vß╗ñ D╞»ß╗ÜI SPRINT */}
                      <button
                        onClick={() => {
                          setActiveSprintForTask(sprint.sprintId); // L╞░u ID cß╗ºa sprint hiß╗çn tß║íi
                          setOpenCreateTask(true);
                        }}
                        className='flex items-center gap-2 ...'
                      >
                        <Plus className='w-4 h-4' />
                        Tß║ío nhiß╗çm vß╗Ñ
                      </button>
                    </div>
                  </div>
                );
              })}

              {/* BACKLOG (Unassigned) */}
              <div className='rounded-3xl bg-white border border-gray-100 shadow-sm p-6 mt-8'>
                <div className='flex items-center mb-6 pl-2 pr-1'>
                  <div className='w-4 h-4 rounded border border-gray-300 mr-4 flex-shrink-0' />
                  <h3 className='text-[16px] font-bold text-gray-900'>Backlog</h3>
                  <div className='flex-1' />
                  <div className='flex items-center gap-3'>
                    <button
                      onClick={handleQuickCreateSprint}
                      className='h-[34px] px-5 border border-gray-200 bg-white rounded-full text-[13px] font-medium text-gray-700 hover:bg-gray-50 transition-colors shadow-sm'
                    >
                      Tß║ío Sprint
                    </button>
                  </div>
                </div>

                <ColumnHeaders />
                <div className='min-h-[50px] mb-4'>
                  {filteredBacklogItems.map((it) => (
                    <WorkItem
                      key={it.workItemId || it.id}
                      it={it}
                      itemOrder={itemOrders[it.workItemId || it.id]}
                      onClick={async (task) => {
                        try {
                          const res = await productBacklogService.getWorkItemById(
                            projectId,
                            task.workItemId || task.id,
                          );
                          setSelectedTask(res?.data ? { ...task, ...res.data } : task);
                        } catch (e) {
                          console.error(e);
                          setSelectedTask(task);
                        }
                        setOpenUpdateTask(true);
                      }}
                    />
                  ))}
                </div>

                <div className='flex items-center gap-6 mt-4 pl-2'>
                  <button
                    onClick={() => {
                      setActiveSprintForTask(null); // Backlog th├¼ ─æß╗â null
                      setOpenCreateTask(true);
                    }}
                    className='flex items-center gap-2 ...'
                  >
                    <Plus className='w-4 h-4' />
                    Tß║ío nhiß╗çm vß╗Ñ
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Modals */}
      <CreateEpicModal
        open={openCreateEpic}
        onClose={() => setOpenCreateEpic(false)}
        onSubmit={async (payload) => {
          try {
            const apiPayload = {
              title: payload.name,
              name: payload.name,
              description: payload.description,
              endDate: payload.endDate,
            };
            const res = await productBacklogService.createEpic(projectId, apiPayload);
            if (res && res.isSuccess === false) {
              toast.error('Lß╗ùi khi tß║ío epic');
              return;
            }
            toast.success('Tß║ío Epic th├ánh c├┤ng');
            setOpenCreateEpic(false);
            if (res?.data) {
              setEpics((prev) => [...prev, res.data]);
            } else {
              fetchData(projectId);
            }
          } catch {
            toast.error('Lß╗ùi mß║íng khi tß║ío Epic');
          }
        }}
      />

      <StartSprintModal
        open={openStartSprint}
        sprint={selectedSprintAction}
        issueCount={selectedSprintAction?.items?.length || 0}
        onClose={() => setOpenStartSprint(false)}
        onSubmit={async (payload) => {
          try {
            if (!selectedSprintAction) return;

            // Chuß║⌐n bß╗ï payload khß╗¢p vß╗¢i DateOnly cß╗ºa Backend
            const startPayload = {
              startDate: formatToDateOnly(payload.startDate),
              endDate: formatToDateOnly(payload.endDate),
            };

            const resStart = await productBacklogService.startSprint(
              projectId,
              selectedSprintAction.sprintId,
              startPayload,
            );

            if (resStart && resStart.isSuccess !== false) {
              toast.success('Bß║»t ─æß║ºu Sprint th├ánh c├┤ng');

              // Cß║¡p nhß║¡t State tß║íi chß╗ù ─æß╗â n├║t ─æß╗òi trß║íng th├íi ngay lß║¡p tß╗⌐c
              setSprints((prevSprints) =>
                prevSprints.map((s) =>
                  s.sprintId === selectedSprintAction.sprintId
                    ? { ...s, status: 'ACTIVE' } // ├ëp trß║íng th├íi th├ánh ACTIVE ─æß╗â khß╗¢p ─æiß╗üu kiß╗çn hiß╗ân thß╗ï
                    : s,
                ),
              );

              setOpenStartSprint(false);
              fetchData(projectId); // ─Éß╗ông bß╗Ö lß║íi vß╗¢i Server
            }
          } catch (err) {
            toast.error('Lß╗ùi khi bß║»t ─æß║ºu Sprint');
          }
        }}
      />

      <CompleteSprintModal
        open={openCompleteSprint}
        sprint={selectedSprintAction}
        sprints={sprints}
        onClose={() => setOpenCompleteSprint(false)}
        onSubmit={async (payload) => {
          try {
            if (!selectedSprintAction) return;

            // Payload nhß║¡n tß╗½ Modal bao gß╗ôm:
            // incompleteItemsOption ("ToBacklog", "ToNextPlannedSprint", "CreateNewSprint")
            // targetSprintId (ID cß╗ºa sprint mß╗¢i hoß║╖c kß║┐ tiß║┐p)
            // newSprintName (T├¬n sprint mß╗¢i nß║┐u chß╗ìn CreateNewSprint)

            const completePayload = {
              incompleteItemsOption: payload.incompleteItemsOption,
              targetSprintId: payload.targetSprintId,
              newSprintName: payload.newSprintName || '',
            };

            console.log('Payload gß╗¡i ─æi thß╗▒c tß║┐:', completePayload);

            const resComp = await productBacklogService.completeSprint(
              projectId,
              selectedSprintAction.sprintId,
              completePayload,
            );

            if (resComp && resComp.isSuccess === false) {
              return toast.error(resComp.message || 'Lß╗ùi khi ho├án th├ánh Sprint');
            }

            toast.success('Ho├án th├ánh Sprint th├ánh c├┤ng');
            setOpenCompleteSprint(false);

            // ≡ƒöä Cß║¡p nhß║¡t UI ngay lß║¡p tß╗⌐c (Optimistic Update)
            // 1. Chuyß╗ân c├íc task ch╞░a xong cß╗ºa sprint vß╗½a ─æ├│ng v├áo Backlog Items
            if (payload.incompleteItemsOption === 'ToBacklog') {
              const undoneItems = selectedSprintAction.items.filter((it) => {
                const status = (it.status?.name || it.status || '').toUpperCase();
                return !['DONE', 'COMPLETED', 'CLOSED'].includes(status);
              });

              setBacklogItems((prev) => [...prev, ...undoneItems]);
            }

            // 2. Loß║íi bß╗Å Sprint vß╗½a ho├án th├ánh khß╗Åi danh s├ích hiß╗ân thß╗ï
            setSprints((prev) => prev.filter((s) => s.sprintId !== selectedSprintAction.sprintId));

            // 3. ─Éß╗ông bß╗Ö lß║íi dß╗» liß╗çu chuß║⌐n tß╗½ Server sau 500ms
            setTimeout(() => {
              fetchData(projectId, false);
            }, 500);
          } catch (err) {
            console.error('COMPLETE ERROR:', err);
            toast.error('Lß╗ùi server khi ho├án th├ánh Sprint');
          }
        }}
      />
      <CreateTaskModal
        open={openCreateTask}
        epics={epics}
        sprints={sprints}
        // Truyß╗ün prop ─æß╗â modal c├│ thß╗â set mß║╖c ─æß╗ïnh nß║┐u cß║ºn (t├╣y code modal cß╗ºa bß║ín)
        initialSprintId={activeSprintForTask}
        onClose={() => {
          setOpenCreateTask(false);
          setActiveSprintForTask(null);
        }}
        onSubmit={async (payload) => {
          try {
            const targetSprintId = payload.sprintId || activeSprintForTask;

            const apiPayload = {
              title: payload.summary,
              description: payload.description,
              type: payload.type,
              status: payload.status,
              priority: payload.priority,
              parentId: payload.epic || null,
              assigneeId: payload.assignee || null,
              dueDate: payload.dueDate,
              storyPoint: payload.points || 0,
              sprintId: targetSprintId || null,
            };

            // ≡ƒÜÇ 1. IGNITION - CREATE
            const resCreate = await productBacklogService.createWorkItem(projectId, apiPayload);

            if (!resCreate || resCreate.isSuccess === false) {
              throw new Error('Create failed');
            }

            const newWorkItemId =
              typeof resCreate.data === 'string'
                ? resCreate.data
                : resCreate.data.workItemId || resCreate.data.id;

            // ≡ƒºá 3. BUILD OPTIMISTIC OBJECT
            const epicName = epics.find((e) => e.id === payload.epic)?.title || '';

            const optimisticItem = {
              ...apiPayload,
              workItemId: newWorkItemId,
              id: newWorkItemId,
              epicName,
              sprintId: targetSprintId || null,
            };

            // ≡ƒ¢æ 4. KH├öNG BAO GIß╗£ setBacklogItems nß║┐u c├│ sprint
            if (targetSprintId) {
              setSprints((prev) =>
                prev.map((s) =>
                  s.sprintId === targetSprintId
                    ? {
                        ...s,
                        items: [...(s.items || []), optimisticItem],
                        itemCount: (s.itemCount || 0) + 1,
                      }
                    : s,
                ),
              );
            } else {
              setBacklogItems((prev) => [...prev, optimisticItem]);
            }

            toast.success(
              targetSprintId ? 'Tß║ío v├á g─âm v├áo Sprint th├ánh c├┤ng!' : 'Tß║ío nhiß╗çm vß╗Ñ th├ánh c├┤ng!',
            );

            setOpenCreateTask(false);
            setActiveSprintForTask(null);

            // ≡ƒöä ─Éß╗ông bß╗Ö server sau 800ms (KH├öNG show loading)
            setTimeout(() => {
              fetchData(projectId, false);
            }, 800);
          } catch (error) {
            console.error('ANTIGRAVITY ERROR:', error);
            toast.error('Lß╗ùi khi tß║ío nhiß╗çm vß╗Ñ');
          }
        }}
      />

      <UpdateTaskModal
        open={openUpdateTask}
        epics={epics}
        sprints={sprints}
        initialData={selectedTask}
        onClose={() => {
          setOpenUpdateTask(false);
          setSelectedTask(null);
        }}
        onSubmit={async (payload) => {
          try {
            const apiPayload = {
              title: payload.summary,
              description: payload.description,
              type: payload.type,
              status: payload.status,
              priority: payload.priority,
              parentId: payload.epic || null,
              assigneeId: payload.assignee || null,
              dueDate: payload.dueDate,
              storyPoint: payload.points || 0,
            };

            const currentSprintId = selectedTask?.sprintId;
            const newSprintId = payload.sprintId;
            const workItemId = payload.id;

            // 1. UPDATE CHI TIß║╛T
            const resUpdate = await productBacklogService.updateWorkItem(
              projectId,
              workItemId,
              apiPayload,
            );
            if (!resUpdate || resUpdate.isSuccess === false) {
              throw new Error('Update failed');
            }

            // 2. DI CHUYß╗éN SPRINT (Nß║╛U C├ô THAY ─Éß╗öI)
            if (currentSprintId !== newSprintId) {
              if (!newSprintId) {
                // Nß║┐u sprintId mß╗¢i kh├┤ng c├│, th├¼ vß╗ü backlog
                await productBacklogService.moveWorkItemToBacklog(projectId, workItemId);
              } else {
                await productBacklogService.moveWorkItemToSprint(
                  projectId,
                  workItemId,
                  newSprintId,
                );
              }
            }

            toast.success('Cß║¡p nhß║¡t nhiß╗çm vß╗Ñ th├ánh c├┤ng!');
            setOpenUpdateTask(false);
            setSelectedTask(null);

            // ─Éß╗ông bß╗Ö danh s├ích
            fetchData(projectId, false);
          } catch (error) {
            console.error('UPDATE ERROR:', error);
            toast.error('Lß╗ùi khi cß║¡p nhß║¡t nhiß╗çm vß╗Ñ');
          }
        }}
      />
    </div>
  );
}

'use client';
import PageShell from '@/shared/components/PageShell';
import { useEffect, useMemo, useState, useCallback } from 'react';
import StudentTabs from '@/shared/components/StudentTabs';
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  useSensor,
  useSensors,
  closestCorners,
  useDroppable,
} from '@dnd-kit/core';

import { SortableContext, useSortable, verticalListSortingStrategy } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

import { productBacklogService } from '@/services/productbacklog.service';
import { ProjectService } from '@/services/projectService';
import { useToast } from '@/providers/ToastProvider';

// Import Modal
import UpdateTaskModal from '@/shared/components/UpdateTaskModal';

// CH├Ü ├¥: ─Éß╗òi ID khß╗¢p ho├án to├án vß╗¢i Enum trß║ú vß╗ü tß╗½ Backend (Th╞░ß╗¥ng l├á VIß║╛T HOA)
const COLUMNS = [
  { id: 'Todo', title: 'To Do', underline: 'bg-gray-700' },
  { id: 'InProgress', title: 'In Progress', underline: 'bg-blue-600' },
  { id: 'Review', title: 'In Review', underline: 'bg-yellow-500' },
  { id: 'Done', title: 'Done', underline: 'bg-green-500' },
];

export default function Board() {
  const [items, setItems] = useState([]);
  const [query, setQuery] = useState('');
  const [activeId, setActiveId] = useState(null);
  const [projectId, setProjectId] = useState(null);
  const toast = useToast();

  // Modal states
  const [openUpdateTask, setOpenUpdateTask] = useState(false);
  const [selectedTask, setSelectedTask] = useState(null);
  const [epics, setEpics] = useState([]);
  const [sprints, setSprints] = useState([]);

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }));

  useEffect(() => {
    const fetchProjectId = async () => {
      try {
        const res = await ProjectService.getAll({ PageNumber: 1, PageSize: 1 });
        if (res?.data?.items?.length > 0) {
          setProjectId(res.data.items[0].projectId);
        }
      } catch {
        toast.error('Kh├┤ng lß║Ñy ─æ╞░ß╗úc project');
      }
    };
    fetchProjectId();
  }, [toast]);

  // H├ám fetch dß╗» liß╗çu (D├╣ng useCallback ─æß╗â ─æß╗ông bß╗Ö nh╞░ b├¬n Backlog)
  const fetchSprints = useCallback(
    async (showLoading = true) => {
      if (!projectId) return;
      try {
        const [sprintsRes, epicsRes] = await Promise.all([
          productBacklogService.getWorkItemsBacklog(projectId),
          productBacklogService.getEpics(projectId),
        ]);

        setEpics(epicsRes?.data?.items || epicsRes?.data || []);
        let sprintsData = sprintsRes?.data?.sprints || [];
        setSprints(sprintsData);

        const activeSprint =
          sprintsData.find((s) => s.status?.toUpperCase() === 'ACTIVE') || sprintsData[0];

        if (activeSprint) {
          const itemsToMap = activeSprint.featureWorkItems || activeSprint.items || [];
          const mappedItems = itemsToMap.map((it, idx) => ({
            id: it.workItemId || it.id,
            displayId: it.key || `ISSUE-${idx + 1}`,
            title: it.title || it.name,
            type: it.type || 'UserStory',
            priority: it.priority || 'MEDIUM',
            points: it.storyPoint || 0,
            assignee: it.assigneeName || 'ΓÇö',
            status: it.status || 'Todo', // Chuß║⌐n h├│a viß║┐t hoa
            sprintId: activeSprint.sprintId,
            parentId: it.parentId,
          }));
          setItems(mappedItems);
        }
      } catch (err) {
        toast.error('Lß╗ùi khi tß║úi dß╗» liß╗çu');
      }
    },
    [projectId, toast],
  );

  useEffect(() => {
    fetchSprints();
  }, [fetchSprints]);

  const byColumn = useMemo(() => {
    const map = Object.fromEntries(COLUMNS.map((c) => [c.id, []]));
    items.forEach((it) => {
      // Kh├┤ng d├╣ng .toUpperCase() ß╗ƒ ─æ├óy nß╗»a ─æß╗â khß╗¢p ch├¡nh x├íc ID
      if (map[it.status]) map[it.status].push(it);
    });
    return map;
  }, [items]);

  // Xß╗¡ l├╜ Click mß╗ƒ Modal
  const handleTaskClick = async (task) => {
    try {
      const res = await productBacklogService.getWorkItemById(projectId, task.id);
      setSelectedTask(res?.data ? { ...task, ...res.data } : task);
      setOpenUpdateTask(true);
    } catch (e) {
      setSelectedTask(task);
      setOpenUpdateTask(true);
    }
  };

  // H├ám Submit Cß║¡p Nhß║¡t (Copy logic chuß║⌐n tß╗½ Backlog sang)
  const handleUpdateSubmit = async (payload) => {
    try {
      const apiPayload = {
        title: payload.summary,
        description: payload.description,
        type: payload.type,
        status: payload.status,
        priority: payload.priority,
        parentId: payload.epic || null,
        assigneeId: payload.assignee || null,
        dueDate: payload.dueDate,
        storyPoint: payload.points || 0,
      };

      const workItemId = payload.id;
      const currentSprintId = selectedTask?.sprintId;
      const newSprintId = payload.sprintId;

      // 1. Update chi tiß║┐t
      const resUpdate = await productBacklogService.updateWorkItem(
        projectId,
        workItemId,
        apiPayload,
      );
      if (!resUpdate || resUpdate.isSuccess === false) throw new Error('Update failed');

      // 2. Di chuyß╗ân Sprint nß║┐u cß║ºn
      if (currentSprintId !== newSprintId && newSprintId !== undefined) {
        if (!newSprintId) {
          await productBacklogService.moveWorkItemToBacklog(projectId, workItemId);
        } else {
          await productBacklogService.moveWorkItemToSprint(projectId, workItemId, newSprintId);
        }
      }

      toast.success('Cß║¡p nhß║¡t nhiß╗çm vß╗Ñ th├ánh c├┤ng!');
      setOpenUpdateTask(false);

      // 3. ─Éß╗ông bß╗Ö lß║íi dß╗» liß╗çu board (Kh├┤ng d├╣ng loading ─æß╗â tr├ính nh├íy m├án h├¼nh)
      fetchSprints(false);
    } catch (error) {
      console.error(error);
      toast.error('Lß╗ùi khi cß║¡p nhß║¡t nhiß╗çm vß╗Ñ');
    }
  };

  // Dnd Handlers
  function onDragStart(event) {
    setActiveId(event.active.id);
  }

  function onDragOver(event) {
    const { active, over } = event;
    if (!over) return;
    const activeId = active.id;
    const overId = over.id;
    const activeTask = items.find((i) => i.id === activeId);
    if (!activeTask) return;
    const isOverAColumn = COLUMNS.some((col) => col.id === overId);
    const overColumnId = isOverAColumn ? overId : items.find((i) => i.id === overId)?.status;
    if (!overColumnId || overColumnId === activeTask.status) return;
    setItems((prev) =>
      prev.map((item) => (item.id === activeId ? { ...item, status: overColumnId } : item)),
    );
  }

  async function onDragEnd(event) {
    const { active, over } = event;
    setActiveId(null);
    if (!over) return;
    const activeId = active.id;
    const currentTask = items.find((i) => i.id === activeId);
    if (!currentTask) return;
    try {
      const taskRes = await productBacklogService.getWorkItemById(projectId, activeId);
      if (taskRes && taskRes.data) {
        const d = taskRes.data;
        const payload = {
          title: d.title,
          description: d.description || '',
          type: d.type,
          status: currentTask.status, // Status mß╗¢i tß╗½ state sau khi drag
          priority: d.priority,
          parentId: d.parentId || null,
          assigneeId: d.assigneeId || null,
          storyPoint: d.storyPoint || 0,
        };
        await productBacklogService.updateWorkItem(projectId, activeId, payload);
      }
    } catch (err) {
      console.error('Lß╗ùi cß║¡p nhß║¡t:', err);
    }
  }

  const activeTask = useMemo(() => items.find((it) => it.id === activeId), [activeId, items]);

  return (
    <PageShell>
      <div className='flex flex-col gap-4 mb-4'>
        <StudentTabs />
        <div className='flex items-center gap-2'>
          <div className='w-full max-w-sm border rounded-full px-4 py-2 bg-white'>
            <input
              placeholder='Search tasks...'
              className='bg-transparent outline-none w-full text-sm'
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
          </div>
        </div>
      </div>

      <DndContext
        sensors={sensors}
        collisionDetection={closestCorners}
        onDragStart={onDragStart}
        onDragOver={onDragOver}
        onDragEnd={onDragEnd}
      >
        <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 w-full'>
          {COLUMNS.map((col) => (
            <BoardColumn
              key={col.id}
              column={col}
              tasks={byColumn[col.id].filter((t) =>
                t.title.toLowerCase().includes(query.toLowerCase()),
              )}
              onCardClick={handleTaskClick}
            />
          ))}
        </div>

        <DragOverlay
          dropAnimation={{ duration: 250, easing: 'cubic-bezier(0.18, 0.67, 0.6, 1.22)' }}
        >
          {activeTask ? <IssueCard task={activeTask} isOverlay /> : null}
        </DragOverlay>
      </DndContext>

      {/* MODAL UPDATE */}
      <UpdateTaskModal
        open={openUpdateTask}
        epics={epics}
        sprints={sprints}
        initialData={selectedTask}
        onClose={() => {
          setOpenUpdateTask(false);
          setSelectedTask(null);
        }}
        onSubmit={handleUpdateSubmit}
      />
    </PageShell>
  );
}

function BoardColumn({ column, tasks, onCardClick }) {
  const { setNodeRef, isOver } = useDroppable({ id: column.id });
  return (
    <div className='flex flex-col w-full h-full'>
      <div className='flex items-center gap-2 mb-3'>
        <span className='text-sm font-bold text-gray-700'>{column.title}</span>
        <span className='text-[11px] font-bold bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full'>
          {tasks.length}
        </span>
      </div>
      <div className={`h-1 w-full ${column.underline} mb-4 rounded-full opacity-80`} />
      <div
        ref={setNodeRef}
        className={`flex flex-col gap-4 p-1 min-h-[calc(100vh-300px)] transition-colors rounded-xl ${isOver ? 'bg-gray-50/50' : 'bg-transparent'}`}
      >
        <SortableContext items={tasks.map((t) => t.id)} strategy={verticalListSortingStrategy}>
          {tasks.map((t) => (
            <SortableIssueCard key={t.id} task={t} onClick={onCardClick} />
          ))}
        </SortableContext>
      </div>
    </div>
  );
}

function SortableIssueCard({ task, onClick }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: task.id,
  });
  const style = {
    transform: CSS.Translate.toString(transform),
    transition,
    opacity: isDragging ? 0.3 : 1,
  };
  return (
    <div ref={setNodeRef} style={style} className='touch-none' onClick={() => onClick(task)}>
      <div {...attributes} {...listeners}>
        <IssueCard task={task} />
      </div>
    </div>
  );
}

function IssueCard({ task, isOverlay }) {
  const getPriorityStyle = (priority) => {
    const p = priority?.toUpperCase();
    if (p === 'HIGH') return 'bg-orange-50 text-orange-700';
    if (p === 'LOW') return 'bg-green-50 text-green-700';
    return 'bg-blue-50 text-blue-700';
  };

  return (
    <div
      className={`bg-white border p-4 rounded-[24px] shadow-sm flex flex-col gap-3 transition-all relative ${isOverlay ? 'cursor-grabbing border-blue-500 shadow-xl scale-105' : 'cursor-grab border-gray-100 hover:shadow-md hover:border-gray-200'}`}
    >
      <div className='flex justify-between items-start'>
        <div className='px-3 py-1 border border-gray-100 rounded-full text-[10px] font-bold text-gray-400 bg-white uppercase'>
          {task.type || 'User Story'}
        </div>
      </div>
      <div className='mt-0.5'>
        <div className='text-[18px] font-extrabold text-gray-900 leading-none mb-2'>
          {task.displayId}
        </div>
        <div
          className='text-[14px] font-medium text-gray-600 line-clamp-3 leading-snug'
          dangerouslySetInnerHTML={{ __html: task.title }}
        />
      </div>
      <div className='flex flex-wrap gap-2 items-center mt-1'>
        <span
          className={`px-2.5 py-1 text-[11px] font-bold rounded-full ${getPriorityStyle(task.priority)}`}
        >
          {task.priority?.charAt(0).toUpperCase() + task.priority?.slice(1).toLowerCase()}
        </span>
        {task.points > 0 && (
          <span className='w-6 h-6 flex items-center justify-center text-[11px] font-bold bg-blue-50 text-blue-500 rounded-full border border-blue-100'>
            {task.points}
          </span>
        )}
      </div>
      <div className='flex items-center mt-1'>
        <div className='w-8 h-8 rounded-full flex items-center justify-center bg-gray-100 text-gray-400 text-[10px] font-bold uppercase'>
          {task.assignee?.charAt(0).toUpperCase()}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'next/navigation';
import {
  Table,
  Button,
  Modal,
  Form,
  Input,
  Select,
  DatePicker,
  message,
  Typography,
  Skeleton,
  Empty,
  Tooltip,
} from 'antd';
import {
  PlusOutlined,
  FileTextOutlined,
  FilterOutlined,
  EditOutlined,
  DeleteOutlined,
} from '@ant-design/icons';
import { LogBookService } from '@/services/logBook.service';
import { InternshipGroupService } from '@/services/internshipGroup.service';
import dayjs from 'dayjs';

const { Title, Text } = Typography;
const { TextArea } = Input;

export default function DailyReport() {
  const [messageApi, contextHolder] = message.useMessage();
  const searchParams = useSearchParams();
  const internshipId = searchParams.get('id');

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);

  // Pagination & Filters
  const [pageNumber, setPageNumber] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [statusFilter, setStatusFilter] = useState(undefined);
  const [sortOrder, setSortOrder] = useState('desc'); // api default usually implies descending for date, we can pass it if supported
  const [currentId, setCurrentId] = useState(internshipId);

  // Modal & Edit State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [form] = Form.useForm();

  const [studentId, setStudentId] = useState(null);

  useEffect(() => {
    // Extract studentId from the JWT token
    const tokenRaw = sessionStorage.getItem('accessToken');
    if (tokenRaw) {
      try {
        let token = tokenRaw;
        if (!token.startsWith('ey')) {
          const parsed = JSON.parse(tokenRaw);
          token = parsed?.accessToken || parsed?.data?.accessToken;
        }
        if (token) {
          const payloadBase64 = token.split('.')[1];
          const payloadStr = atob(payloadBase64);
          const payload = JSON.parse(payloadStr);
          const id =
            payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] ||
            payload.sub;
          setStudentId(id);
        }
      } catch (e) {
        console.error('Failed to decode JWT to get StudentId', e);
      }
    }
  }, []);

  const fetchLogbooks = useCallback(async () => {
    let idToFetch = currentId || internshipId;
    setLoading(true);

    try {
      // If no ID is present in URL, try to fetch the first group for this student
      if (!idToFetch) {
        const groupsRes = await InternshipGroupService.getAll();
        if (groupsRes && groupsRes.isSuccess !== false && groupsRes.data) {
          const items = groupsRes.data.items || groupsRes.items || [];
          if (items.length > 0) {
            idToFetch = items[0].internshipId;
            setCurrentId(idToFetch);
          }
        }
      }

      if (!idToFetch) {
        setLoading(false);
        return;
      }

      const res = await LogBookService.getAll({
        InternshipId: idToFetch,
        Status: statusFilter,
        PageNumber: pageNumber,
        PageSize: pageSize,
        SortColumn: 'dateReport',
        SortOrder: sortOrder,
      });

      if (res && res.isSuccess !== false) {
        // Assume API returns { data: { items: [], totalCount: ... } } or similar
        // Adjust according to standard list response
        let items = [];
        if (Array.isArray(res.data)) {
          items = res.data;
        } else if (res.data?.items && Array.isArray(res.data.items)) {
          items = res.data.items;
        } else if (res.data && typeof res.data === 'object' && !Array.isArray(res.data)) {
          // Maybe it's a single item returned as just an object inside data
          items = [res.data];
        } else if (Array.isArray(res.items)) {
          items = res.items;
        }

        const totalItems = res.data?.totalCount || res.totalCount || items.length;

        setData(items);
        setTotal(totalItems);
      }
    } finally {
      setLoading(false);
    }
  }, [internshipId, currentId, statusFilter, pageNumber, pageSize, sortOrder, messageApi]);

  useEffect(() => {
    fetchLogbooks();
  }, [fetchLogbooks]);

  const handleTableChange = (pagination, filters, sorter) => {
    setPageNumber(pagination.current);
    setPageSize(pagination.pageSize);

    if (sorter.field === 'dateReport' && sorter.order) {
      setSortOrder(sorter.order === 'ascend' ? 'asc' : 'desc');
    } else if (!sorter.order) {
      setSortOrder(undefined);
    }
  };

  const handleCreateOrUpdate = async (values) => {
    const targetId = currentId || internshipId;
    if (!targetId) {
      messageApi.error('Missing Internship ID');
      return;
    }
    if (!studentId) {
      messageApi.error('User context missing (Student ID not found)');
      return;
    }

    setSubmitting(true);
    try {
      const payload = {
        internshipId: targetId,
        studentId,
        summary: values.summary,
        issue: values.issue || '',
        plan: values.plan,
        dateReport: dayjs(values.dateReport).format('YYYY-MM-DDTHH:mm:ss.SSS[Z]'),
        status: values.status !== undefined ? values.status : 1, // Default to Submitted
      };

      let res;
      if (editingId) {
        payload.logbookId = editingId;
        res = await LogBookService.update(editingId, payload);
      } else {
        res = await LogBookService.create(payload);
      }

      if (res && res.isSuccess !== false) {
        messageApi.success(
          editingId ? 'Logbook updated successfully!' : 'Logbook created successfully!',
        );
        closeModal();
        fetchLogbooks(); // Refresh table
      } else {
        messageApi.error(
          res?.message ||
            res?.data?.message ||
            (editingId ? 'Failed to update logbook' : 'Failed to create logbook'),
        );
      }
    } catch (error) {
      console.error(error);
      messageApi.error('An unexpected error occurred');
    } finally {
      setSubmitting(false);
    }
  };

  const handleEdit = (record) => {
    setEditingId(record.logbookId);
    form.setFieldsValue({
      dateReport: record.dateReport ? dayjs(record.dateReport) : null,
      status: record.status,
      summary: record.summary,
      issue: record.issue,
      plan: record.plan,
    });
    setIsModalOpen(true);
  };

  const handleDelete = async (id) => {
    try {
      const res = await LogBookService.delete(id);
      if (res && res.isSuccess !== false) {
        messageApi.success('Logbook deleted successfully!');
        if (data.length === 1 && pageNumber > 1) {
          setPageNumber(pageNumber - 1);
        } else {
          fetchLogbooks();
        }
      } else {
        messageApi.error(res?.message || 'Failed to delete logbook');
      }
    } catch {
      messageApi.error('An error occurred during deletion');
    }
  };

  const renderStatus = (status) => {
    const config = {
      0: { label: 'Draft', style: 'bg-orange-50 text-orange-600 border-orange-200 border' },
      1: { label: 'Submit for Approval', style: 'bg-blue-50 text-blue-600 border-blue-200 border' },
      2: { label: 'Approved', style: 'bg-emerald-50 text-emerald-600 border-emerald-200 border' },
      3: { label: 'Rejected', style: 'bg-red-50 text-red-600 border-red-200 border' },
    };
    const c = config[status] || {
      label: 'Unknown',
      style: 'bg-gray-50 text-gray-600 border-gray-200 border',
    };

    return (
      <div className={`inline-flex px-3 py-1 rounded-full text-[13px] font-semibold ${c.style}`}>
        {c.label}
      </div>
    );
  };

  const columns = [
    {
      title: 'Report Date',
      dataIndex: 'dateReport',
      key: 'dateReport',
      sorter: true,
      render: (text) => (
        <span className='font-medium text-gray-700'>
          {text ? new Date(text).toLocaleDateString('en-GB') : 'N/A'}
        </span>
      ),
    },
    {
      title: 'Student',
      dataIndex: 'studentName',
      key: 'studentName',
      render: (text) => <Text className='font-semibold'>{text || 'N/A'}</Text>,
    },
    {
      title: 'Summary',
      dataIndex: 'summary',
      key: 'summary',
      ellipsis: {
        showTitle: false,
      },
      render: (text) => (
        <Tooltip placement='topLeft' title={text}>
          <span className='text-gray-600'>{text}</span>
        </Tooltip>
      ),
    },
    {
      title: 'Issue',
      dataIndex: 'issue',
      key: 'issue',
      ellipsis: {
        showTitle: false,
      },
      render: (text) => (
        <Tooltip placement='topLeft' title={text}>
          <span className='text-gray-600'>{text || '-'}</span>
        </Tooltip>
      ),
    },
    {
      title: 'Status',
      dataIndex: 'status',
      key: 'status',
      render: (status) => renderStatus(status),
    },
    {
      title: 'Action',
      key: 'action',
      width: 120,
      align: 'center',
      render: (_, record) => (
        <div className='flex items-center justify-center gap-2'>
          <Tooltip title='Edit Report'>
            <Button
              type='text'
              icon={
                <EditOutlined className='text-gray-500 hover:text-blue-600 transition-colors' />
              }
              onClick={(e) => {
                e.stopPropagation();
                handleEdit(record);
              }}
              className='hover:bg-blue-50 w-8 h-8 rounded-lg flex items-center justify-center'
            />
          </Tooltip>

          <Tooltip title='Delete Report'>
            <Button
              type='text'
              danger
              icon={
                <DeleteOutlined className='text-gray-400 hover:text-red-500 transition-colors' />
              }
              onClick={(e) => {
                e.stopPropagation();
                Modal.confirm({
                  title: 'Delete Logbook',
                  content: 'Are you sure you want to delete this logbook entry?',
                  okText: 'Yes, Delete',
                  okType: 'danger',
                  cancelText: 'Cancel',
                  onOk: () => handleDelete(record.logbookId),
                  className: 'modern-modal',
                  okButtonProps: { className: 'rounded-lg font-semibold' },
                  cancelButtonProps: { className: 'rounded-lg font-medium' },
                });
              }}
              className='hover:bg-red-50 w-8 h-8 rounded-lg flex items-center justify-center'
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  if (!internshipId && !currentId && !loading && total === 0) {
    return (
      <div className='flex h-[400px] items-center justify-center bg-gray-50/50 rounded-[24px] border border-gray-200/50 m-6'>
        <Empty
          image={Empty.PRESENTED_IMAGE_SIMPLE}
          className='my-auto'
          description={
            <span className='text-gray-500 font-medium'>
              Please select an internship group to view logbooks.
            </span>
          }
        />
      </div>
    );
  }

  return (
    <div className='space-y-6 max-w-[1400px] mx-auto pb-8'>
      {contextHolder}

      <div className='flex items-center justify-between mb-8 mt-4 px-2'>
        <div>
          <Title level={2} className='!mb-1 tracking-tight text-gray-900'>
            Daily Report
          </Title>
          <Text className='text-gray-500 text-[15px]'>
            Manage and submit your daily internship logbooks
          </Text>
        </div>
      </div>

      <div className='bg-white rounded-[24px] border border-gray-200/60 shadow-[0_2px_10px_-4px_rgba(0,0,0,0.05)] overflow-hidden'>
        <div className='px-8 py-5 border-b border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4'>
          <div className='flex items-center gap-4'>
            <div className='w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center border border-blue-100 shrink-0'>
              <FileTextOutlined className='text-blue-600 text-lg' />
            </div>

            <Select
              allowClear
              placeholder='Filter by Status'
              value={statusFilter}
              onChange={(val) => {
                setStatusFilter(val);
                setPageNumber(1);
              }}
              className='w-48 shadow-sm'
              rootClassName='custom-select-rounded'
              popupClassName='!rounded-xl shadow-lg border border-gray-100'
              suffixIcon={<FilterOutlined />}
              options={[
                { value: 0, label: 'Draft' },
                { value: 1, label: 'Submitted' },
                { value: 2, label: 'Approved' },
                { value: 3, label: 'Rejected' },
              ]}
            />
          </div>

          <Button
            type='primary'
            icon={<PlusOutlined />}
            onClick={() => setIsModalOpen(true)}
            className='bg-black hover:bg-gray-800 text-white rounded-xl h-10 px-6 font-semibold shadow-sm border-0 transition-all hover:scale-105'
          >
            Create Report
          </Button>
        </div>

        <div className='px-4 pb-4 mt-2'>
          {loading ? (
            <div className='p-6 space-y-4'>
              <Skeleton active paragraph={{ rows: 6 }} />
            </div>
          ) : (
            <Table
              dataSource={data}
              columns={columns}
              rowKey='logbookId'
              onChange={handleTableChange}
              pagination={{
                current: pageNumber,
                pageSize: pageSize,
                total: total,
                showSizeChanger: true,
                className: 'px-6 mb-2',
              }}
              rowClassName='hover:bg-gray-50/50 transition-colors cursor-default'
              locale={{
                emptyText: (
                  <div className='py-12'>
                    <Empty
                      image={Empty.PRESENTED_IMAGE_SIMPLE}
                      description={
                        <span className='text-gray-400 font-medium'>
                          No logbooks found for this group
                        </span>
                      }
                    />
                  </div>
                ),
              }}
            />
          )}
        </div>
      </div>

      <Modal
        title={
          <div className='flex items-center gap-3 py-2 border-b border-gray-100 mb-4'>
            <div className='w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600 border border-blue-100 shrink-0'>
              {editingId ? (
                <EditOutlined className='text-lg' />
              ) : (
                <PlusOutlined className='text-lg' />
              )}
            </div>
            <div>
              <h3 className='text-lg font-bold text-gray-900 m-0'>
                {editingId ? 'Edit Daily Report' : 'Create Daily Report'}
              </h3>
              <p className='text-sm text-gray-500 font-medium m-0 mt-0.5'>
                {editingId
                  ? 'Update your submitted logbook details'
                  : 'Submit your internship progress'}
              </p>
            </div>
          </div>
        }
        open={isModalOpen}
        // onCancel={closeModal}
        confirmLoading={submitting}
        onOk={() => form.submit()}
        okText={editingId ? 'Save Changes' : 'Submit Report'}
        cancelText='Cancel'
        className='modern-modal'
        width={700}
        okButtonProps={{
          className:
            'bg-black hover:bg-gray-800 text-white rounded-lg h-10 px-6 font-semibold shadow-sm border-0',
        }}
        cancelButtonProps={{
          className:
            'rounded-lg h-10 px-5 font-medium border-gray-200 hover:border-gray-300 hover:bg-gray-50 text-gray-600',
        }}
      >
        <Form
          form={form}
          layout='vertical'
          onFinish={handleCreateOrUpdate}
          className='mt-4 px-2'
          initialValues={{
            status: 1, // default Submitted
          }}
        >
          <div className='grid grid-cols-1 md:grid-cols-2 gap-x-6'>
            <Form.Item
              label={<span className='text-sm font-semibold text-gray-700'>Report Date</span>}
              name='dateReport'
              rules={[{ required: true, message: 'Please select a date!' }]}
            >
              <DatePicker
                className='w-full h-[44px] rounded-xl'
                format='DD/MM/YYYY'
                disabledDate={(current) => current && current > dayjs().endOf('day')}
              />
            </Form.Item>

            <Form.Item
              label={<span className='text-sm font-semibold text-gray-700'>Status</span>}
              name='status'
              rules={[{ required: true, message: 'Please select a status!' }]}
            >
              <Select
                className='h-[44px]'
                rootClassName='custom-select-rounded'
                popupClassName='!rounded-xl shadow-lg border border-gray-100'
                options={[
                  { value: 0, label: 'Draft' },
                  { value: 1, label: 'Submit for Approval' },
                ]}
              />
            </Form.Item>
          </div>

          <Form.Item
            label={<span className='text-sm font-semibold text-gray-700'>Work Summary</span>}
            name='summary'
            rules={[
              { required: true, message: 'Please enter a summary of your work!' },
              { min: 10, message: 'Summary must be at least 10 characters long.' },
            ]}
          >
            <TextArea
              placeholder='Describe the tasks you worked on today...'
              autoSize={{ minRows: 4, maxRows: 8 }}
              className='rounded-xl p-3'
            />
          </Form.Item>

          <Form.Item
            label={
              <span className='text-sm font-semibold text-gray-700'>
                Issues Encountered (Optional)
              </span>
            }
            name='issue'
          >
            <TextArea
              placeholder='Any blockers or challenges you faced?'
              autoSize={{ minRows: 3, maxRows: 6 }}
              className='rounded-xl p-3'
            />
          </Form.Item>

          <Form.Item
            label={<span className='text-sm font-semibold text-gray-700'>Plan for Next Day</span>}
            name='plan'
            rules={[
              { required: true, message: 'Please outline your plan for the next working day!' },
            ]}
          >
            <TextArea
              placeholder='What are your tasks for tomorrow?'
              autoSize={{ minRows: 3, maxRows: 6 }}
              className='rounded-xl p-3'
            />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}

'use client';

import { useEffect, useState, useRef, useCallback } from 'react';
import SearchBar from '@/shared/components/SearchBar';
import Footer from '@/shared/components/Footer';
import { Popconfirm } from 'antd';
import dayjs from 'dayjs';
import Card from '@/shared/components/Card';
import StakeholderIssueService from '@/services/stakeholderIssue';
import { StakeholderService } from '@/services/stakeholder';
import {
  CheckCircleOutlined,
  DeleteOutlined,
  SyncOutlined,
  CloseOutlined,
} from '@ant-design/icons';
import { useToast } from '@/providers/ToastProvider';
import { ProjectService } from '@/services/projectService';
export default function IssueTab() {
  const toast = useToast();
  const [projectId, setProjectId] = useState(null);
  const [issues, setIssues] = useState([]);
  const [stakeholders, setStakeholders] = useState([]);
  const [loading, setLoading] = useState(false);

  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [total, setTotal] = useState(0);

  const [openIssueForm, setOpenIssueForm] = useState(false);

  const [issueForm, setIssueForm] = useState({
    title: '',
    description: '',
    stakeholderId: '',
  });

  const [issueDetail, setIssueDetail] = useState(null);

  const handleViewDetail = async (id) => {
    const res = await StakeholderIssueService.getById(id);
    setIssueDetail(res.data);
  };

  useEffect(() => {
    const t = setTimeout(() => {
      setDebouncedSearch(search);
      setPage(1);
    }, 500);
    return () => clearTimeout(t);
  }, [search]);

  const tableBodyRef = useRef(null);

  useEffect(() => {
    tableBodyRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
  }, [page, pageSize]);

  const totalPages = Math.ceil(total / pageSize);
  const handleSaveIssue = async () => {
    if (!issueForm.title || !issueForm.stakeholderId) {
      toast.warning('Please fill required fields');
      return;
    }

    try {
      await StakeholderIssueService.create({
        title: issueForm.title,
        description: issueForm.description,
        stakeholderId: issueForm.stakeholderId,
        projectId,
      });

      toast.success('Issue created successfully');

      setOpenIssueForm(false);
      setIssueForm({ title: '', description: '', stakeholderId: '' });
      fetchIssues();
    } catch {
      toast.error('Failed to create issue');
    }
  };
  const handleDelete = async (id) => {
    try {
      await StakeholderIssueService.delete(id);
      toast.success('Issue deleted successfully');
      fetchIssues();
    } catch {
      toast.error('Failed to delete issue');
    }
  };

  const handleToggleStatus = async (issue) => {
    try {
      const newStatus = issue.status === 'Resolved' ? 'Open' : 'Resolved';
      await StakeholderIssueService.updateStatus(issue.id, newStatus);

      toast.success(newStatus === 'Resolved' ? 'Issue marked as resolved' : 'Issue reopened');

      fetchIssues();
    } catch {
      toast.error('Failed to update issue status');
    }
  };

  useEffect(() => {
    const fetchProjectId = async () => {
      try {
        const res = await ProjectService.getAll({
          PageNumber: 1,
          PageSize: 1,
        });

        if (res?.data?.items?.length > 0) {
          setProjectId(res.data.items[0].projectId);
        }
      } catch {
        toast.error('Cannot load project');
      }
    };

    fetchProjectId();
  }, []);

  const fetchStakeholders = useCallback(async () => {
    if (!projectId) return;

    const res = await StakeholderService.getByProject(projectId);
    if (res?.data?.items) {
      setStakeholders(res.data.items);
    }
  }, [projectId]);

  const fetchIssues = useCallback(async () => {
    if (!projectId) return;

    try {
      setLoading(true);

      const params = {
        projectId,
        PageIndex: page,
        PageSize: pageSize,
        OrderBy: 'createdAt desc',
      };

      if (debouncedSearch) {
        params.Search = debouncedSearch;
      }

      const res = await StakeholderIssueService.getAll(params);

      if (res?.data?.items) {
        setIssues(res.data.items);
        setTotal(res.data.totalCount || 0);
      }
    } finally {
      setLoading(false);
    }
  }, [projectId, page, pageSize, debouncedSearch]);

  useEffect(() => {
    fetchStakeholders();
  }, [fetchStakeholders]);

  useEffect(() => {
    fetchIssues();
  }, [fetchIssues]);
  return (
    <>
      <Card>
        <SearchBar
          placeholder='Search issue...'
          value={search}
          onChange={setSearch}
          showFilter
          showAction
          actionLabel='Add issue'
          onActionClick={() => setOpenIssueForm(true)}
        />

        <div className='flex-1 flex flex-col min-h-0'>
          {loading ? (
            <div className='flex items-center justify-center py-12'>
              <div className='h-8 w-8 animate-spin rounded-full border-t-2 border-slate-400 border-r-2 border-r-transparent'></div>
            </div>
          ) : issues.length === 0 ? (
            <div className='flex-1 flex items-center justify-center'>
              <p className='text-slate-400'>No issues found.</p>
            </div>
          ) : (
            <div className='flex-1 flex flex-col min-h-0 mt-5'>
              <div className='flex-1 overflow-auto' ref={tableBodyRef}>
                <table className='w-full text-left border-collapse table-fixed min-w-[900px]'>
                  <thead className='bg-slate-50 sticky top-0 z-10 border-b border-slate-200'>
                    <tr>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500 w-[60px]'>
                        STT
                      </th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500'>Title</th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500'>
                        Stakeholder
                      </th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500'>
                        Description
                      </th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500'>Status</th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500'>
                        Created Date
                      </th>
                      <th className='px-6 py-4 text-xs font-semibold text-slate-500 text-right'>
                        Actions
                      </th>
                    </tr>
                  </thead>
                  <tbody className='divide-y divide-slate-100'>
                    {issues.map((i, index) => (
                      <tr
                        key={i.id}
                        onClick={() => handleViewDetail(i.id)}
                        className='hover:bg-slate-50/80 transition-colors cursor-pointer'
                      >
                        <td className='px-6 py-4 text-sm text-slate-600'>
                          {(page - 1) * pageSize + index + 1}
                        </td>
                        <td className='px-6 py-4 text-sm text-slate-600'>{i.title}</td>
                        <td className='px-6 py-4 text-sm text-slate-600 truncate'>
                          {stakeholders.find((s) => s.id === i.stakeholderId)?.name || 'Unknown'}
                        </td>
                        <td className='px-6 py-4 text-sm text-slate-600'>
                          <div className='truncate max-w-[300px]' title={i.description}>
                            {i.description || '-'}
                          </div>
                        </td>
                        <td className='px-6 py-4'>
                          <span
                            className={`inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-medium border ${
                              i.status === 'Resolved' || i.status === '─É├ú giß║úi quyß║┐t'
                                ? 'bg-green-50 text-green-700 border-green-200'
                                : 'bg-orange-50 text-orange-700 border-orange-200'
                            }`}
                          >
                            {i.status === 'Resolved' || i.status === '─É├ú giß║úi quyß║┐t' ? (
                              <CheckCircleOutlined />
                            ) : (
                              <SyncOutlined spin />
                            )}
                            {i.status || '─Éang xß╗¡ l├╜'}
                          </span>
                        </td>
                        <td className='px-6 py-4 text-sm text-slate-600'>
                          {dayjs(i.createdAt).format('DD/MM/YYYY')}
                        </td>
                        <td className='px-6 py-4 text-right'>
                          <div className='flex items-center justify-end gap-2'>
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                handleToggleStatus(i);
                              }}
                              className='text-slate-400 hover:text-blue-600 px-2'
                            >
                              {i.status === 'Resolved' ? 'Reopen' : 'Resolve'}
                            </button>
                            <Popconfirm
                              title='Delete'
                              onConfirm={(e) => {
                                e?.stopPropagation();
                                handleDelete(i.id);
                              }}
                            >
                              <button
                                onClick={(e) => e.stopPropagation()}
                                className='text-slate-400 hover:text-red-600 px-2'
                              >
                                <DeleteOutlined />
                              </button>
                            </Popconfirm>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </Card>
      {(total > 0 || page > 1) && (
        <div className='flex-none mt-5'>
          <Footer
            total={total}
            page={page}
            pageSize={pageSize}
            totalPages={totalPages}
