    name: '',
    type: 'Real',
    role: '',
    description: '',
    email: '',
    phoneNumber: '',
  });

  const handleSaveStakeholder = async () => {
    if (!stakeholderForm.name || !stakeholderForm.email) {
      toast.warning('Name v├á Email l├á bß║»t buß╗Öc');
      return;
    }

    // const payload = {
    //   projectId: '670c5dc7-a816-40dd-a5b8-fe5bbcf5eb77',
    //   ...stakeholderForm,
    // };
    if (!projectId) {
      toast.error('Ch╞░a x├íc ─æß╗ïnh project');
      return;
    }

    const payload = {
      projectId,
      ...stakeholderForm,
    };

    try {
      if (editingStakeholderId) {
        await StakeholderService.update(editingStakeholderId, payload);
