const API_BASE = '/api/proxy';

async function request(path, options = {}) {
  let token = null;

  if (typeof window !== 'undefined') {
    const raw = sessionStorage.getItem('accessToken');

    if (raw) {
      try {
        if (raw.startsWith('ey')) {
          token = raw;
        } else {
          const parsed = JSON.parse(raw);
          token = parsed?.accessToken || parsed?.data?.accessToken || null;
        }
      } catch {
        token = null;
      }
    }
  }

  const isFormData = options.body instanceof FormData;
  const headers = {
    ...(options.headers || {}),
  };
  if (!isFormData && !headers['Content-Type']) {
    headers['Content-Type'] = 'application/json';
  }
  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }
  const res = await fetch(`${API_BASE}${path}`, {
    ...options,
    headers,
  });
  const contentType = res.headers.get('content-type');
  let data = null;

  if (contentType && contentType.includes('application/json')) {
    const text = await res.text();
    data = text ? JSON.parse(text) : null;
  } else {
    data = await res.text();
  }

  if (!res.ok) {
    // if (res.status === 401 && typeof window !== 'undefined') {
    //   const authHeader = res.headers.get('www-authenticate') || '';
    //   if (authHeader.includes('invalid_token') || authHeader.includes('expired') || !authHeader) {
    //     sessionStorage.removeItem('accessToken');
    //     window.location.href = '/login';
    //   }
    // }
    if (!res.ok) {
      if (res.status === 401 && typeof window !== 'undefined') {
        try {
          // thß╗¡ refresh token
          const refreshRes = await fetch('/api/auth', {
            method: 'PUT',
            credentials: 'include',
          });

          if (refreshRes.ok) {
            const { accessToken } = await refreshRes.json();
            sessionStorage.setItem('accessToken', accessToken);

            // retry request ban ─æß║ºu
            const retryRes = await fetch(`${API_BASE}${path}`, {
              ...options,
              headers: {
                ...headers,
                Authorization: `Bearer ${accessToken}`,
              },
            });

            return retryRes.json();
          }
        } catch (e) {
          console.error('Refresh token failed', e);
        }
      }

      return {
        isSuccess: false,
        status: res.status,
        data,
      };
    }

    return {
      isSuccess: false,
      status: res.status,
      data,
    };
  }

  return data;
}

export const httpGet = (path, options) => request(path, { method: 'GET', ...options });

export const httpDelete = (path, options) => request(path, { method: 'DELETE', ...options });

export const httpPost = (path, body, options = {}) =>
  request(path, {
    method: 'POST',
    body: body instanceof FormData ? body : JSON.stringify(body),
    ...options,
  });

export const httpPut = (path, body, options = {}) =>
  request(path, {
    method: 'PUT',
    body: body instanceof FormData ? body : JSON.stringify(body),
    ...options,
  });

export const httpPatch = (path, body, options = {}) =>
  request(path, {
    method: 'PATCH',
    body: body instanceof FormData ? body : JSON.stringify(body),
    ...options,
  });
export default {
  httpGet,
  httpPost,
  httpPut,
  httpDelete,
  httpPatch,
};

'use client';

import { Upload } from 'antd';
import ImgCrop from 'antd-img-crop';
import { LoadingOutlined, PlusOutlined } from '@ant-design/icons';
import { useState } from 'react';
import { useToast } from '@/providers/ToastProvider';

export default function AvatarUploader({ value, onChange, size = 116, fullName }) {
  const [loading, setLoading] = useState(false);
  const toast = useToast();

  const getInitials = (name) => {
    if (!name) return '';
    const words = name.trim().split(' ');
    if (words.length === 1) return words[0].charAt(0).toUpperCase();
    return (words[0].charAt(0) + words[1].charAt(0)).toUpperCase();
  };

  const beforeUpload = (file) => {
    const isImage = file.type === 'image/jpeg' || file.type === 'image/png';
    if (!isImage) {
      toast.error('Only JPG / PNG is supported');
      return false;
    }

    const isLt2M = file.size / 1024 / 1024 < 2;
    if (!isLt2M) {
      toast.error('Image must be less than 2MB');
      return false;
    }

    setLoading(true);

    const reader = new FileReader();
    reader.onload = () => {
      onChange?.(reader.result);
      setLoading(false);

      toast.success('Update avatar successfully');
    };

    reader.readAsDataURL(file);
    return false;
  };

  return (
    <ImgCrop rotationSlider>
      <Upload showUploadList={false} beforeUpload={beforeUpload}>
        <div
          className='group relative flex cursor-pointer items-center justify-center overflow-hidden rounded-full border border-slate-300 bg-slate-200 hover:border-red-400'
          style={{ width: size, height: size }}
        >
          {value ? (
            <>
              <img
                src={value}
                alt='avatar'
                className='h-full w-full object-cover'
                draggable={false}
              />
              <div className='absolute inset-0 flex flex-col items-center justify-center bg-black/40 text-white opacity-0 transition-opacity group-hover:opacity-100'>
                <PlusOutlined className='text-xl' />
                <span className='mt-1 text-xs font-semibold'>Edit avatar</span>
              </div>
            </>
          ) : (
            <div className='flex h-full w-full flex-col items-center justify-center text-slate-500'>
              {loading ? (
                <LoadingOutlined className='text-3xl' />
              ) : fullName ? (
                <>
                  <span className='text-4xl font-bold text-slate-700'>{getInitials(fullName)}</span>
                  <div className='absolute inset-0 flex flex-col items-center justify-center bg-black/40 text-white opacity-0 transition-opacity group-hover:opacity-100'>
                    <PlusOutlined className='text-xl' />
                    <span className='mt-1 text-xs font-semibold'>Upload</span>
                  </div>
                </>
              ) : (
                <>
                  <PlusOutlined className='mb-1 text-2xl' />
                  <span className='text-xs font-medium'>Upload</span>
                </>
              )}
            </div>
          )}
        </div>
      </Upload>
    </ImgCrop>
  );
}

